Greedy insertion with incremental cost evaluation across all assigns and random tie-breaking, falling back to new assign creation if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	// Pre‑shuffle the list of assign indices for randomization
	assignIndices := make([]int, MAXASSIGNS)
	limit := 0
	for i := 0; i < MAXASSIGNS; i++ {
		assignIndices[i] = i
		if i < dispatch.AssignsLen && dispatch.Assigns[i].StationCurrent.X != -9999 {
			assignIndices[limit], assignIndices[i] = assignIndices[i], assignIndices[limit]
			limit++
		}
	}

	// Process each order sequentially
	for ordIdx := 0; ordIdx < orderCount; ordIdx++ {
		shipID := total_ship + ordIdx
		bestAssignIdx := -1
		bestCostDelta := 1e18

		// Evaluate all existing assigns
		for attempt := 0; attempt < 2; attempt++ {
			start, end := 0, limit
			if attempt == 1 {
				start, end = limit, dispatch.AssignsLen
			}
			for pos := start; pos < end; pos++ {
				idx := assignIndices[pos]
				if idx >= MAXASSIGNS {
					continue
				}

				// Save original state
				origCost := dispatch.Assigns[idx].Cost

				// Trial insertion
				ok := dispatch.Assigns[idx].AddShip(shipID, oris[ordIdx], dess[ordIdx])
				if !ok {
					dispatch.Assigns[idx].Cost = origCost
					continue
				}
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				delta := newCost - origCost
				if newCost < 0 || delta < 0 {
					delta = 1e17
				}

				// Rollback
				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].Cost = origCost
				dispatch.Assigns[idx].GenRoute()

				// Track best feasible improvement
				if delta < bestCostDelta {
					bestCostDelta = delta
					bestAssignIdx = idx
				}
			}
		}

		// Also consider a brand‑new assign (if within capacity)
		if dispatch.AssignsLen < MAXASSIGNS {
			testIdx := dispatch.AssignsLen
			origCost := dispatch.Assigns[testIdx].Cost

			ok := dispatch.Assigns[testIdx].AddShip(shipID, oris[ordIdx], dess[ordIdx])
			if ok {
				dispatch.Assigns[testIdx].GenRoute()
				newCost := dispatch.Assigns[testIdx].Cost
				delta := newCost - origCost
				if newCost >= 0 && delta >= 0 && delta < bestCostDelta {
					bestCostDelta = delta
					bestAssignIdx = testIdx
				}
				// Always rollback the trial from the empty slot
				dispatch.Assigns[testIdx].RemoveShip(shipID)
				dispatch.Assigns[testIdx].Cost = origCost
				dispatch.Assigns[testIdx].GenRoute()
			}
		}

		// Commit the best found insertion (or create a new assign)
		committed := false
		if bestAssignIdx >= 0 {
			ok := dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[ordIdx], dess[ordIdx])
			if ok {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				committed = true
				if bestAssignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = bestAssignIdx + 1
				}
			}
		}

		// Fallback: force insertion into the next available empty assign
		if !committed {
			fallbackIdx := -1
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen {
					fallbackIdx = i
					break
				}
			}
			if fallbackIdx >= 0 && fallbackIdx < MAXASSIGNS {
				ok := dispatch.Assigns[fallbackIdx].AddShip(shipID, oris[ordIdx], dess[ordIdx])
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					committed = true
					if fallbackIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = fallbackIdx + 1
					}
				}
			}
		}

		// Emergency: last resort — overwrite a placeholder (should rarely happen)
		if !committed && dispatch.AssignsLen < MAXASSIGNS {
			lastIdx := dispatch.AssignsLen
			dispatch.Assigns[lastIdx] = Assign{}
			ok := dispatch.Assigns[lastIdx].AddShip(shipID, oris[ordIdx], dess[ordIdx])
			if ok {
				dispatch.Assigns[lastIdx].GenRoute()
				dispatch.AssignsLen = lastIdx + 1
				committed = true
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

