func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	assignCount := dispatch.AssignsLen

	candidateIndices := make([]int, MAXASSIGNS)
	for i := 0; i < MAXASSIGNS; i++ {
		candidateIndices[i] = i
	}

	activeCount := 0
	for i := 0; i < assignCount; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			candidateIndices[activeCount], candidateIndices[i] = candidateIndices[i], candidateIndices[activeCount]
			activeCount++
		}
	}

	rand.Shuffle(activeCount, func(i, j int) {
		candidateIndices[i], candidateIndices[j] = candidateIndices[j], candidateIndices[i]
	})

	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		bestAssignIdx := -1
		bestDelta := 1e18

		trialOrderId := total_ship + orderIdx
		trialOri := oris[orderIdx]
		trialDes := dess[orderIdx]

		for attempt := 0; attempt < activeCount+1; attempt++ {
			assignIdx := candidateIndices[attempt%len(candidateIndices)]
			if attempt == activeCount {
				assignIdx = assignCount
			}

			if assignIdx >= MAXASSIGNS {
				continue
			}

			oldCost := float64(0)
			if assignIdx < dispatch.AssignsLen && dispatch.Assigns[assignIdx].StationsLen > 0 {
				oldCost = dispatch.Assigns[assignIdx].Cost
			} else if assignIdx < dispatch.AssignsLen {
				oldCost = 0
			} else {
				oldCost = 0
			}

			success := false
			newCost := oldCost
			if assignIdx < dispatch.AssignsLen {
				success = dispatch.Assigns[assignIdx].AddShip(trialOrderId, trialOri, trialDes)
				if success {
					dispatch.Assigns[assignIdx].GenRoute()
					newCost = dispatch.Assigns[assignIdx].Cost
					if newCost < 0 {
						success = false
					}
				}
				if success {
					delta := newCost - oldCost
					if delta < bestDelta {
						bestDelta = delta
						bestAssignIdx = assignIdx
					}
				}
				dispatch.Assigns[assignIdx].RemoveShip(trialOrderId)
				dispatch.Assigns[assignIdx].GenRoute()
			} else {
				if assignCount < MAXASSIGNS {
					success = dispatch.Assigns[assignCount].AddShip(trialOrderId, trialOri, trialDes)
					if success {
						dispatch.Assigns[assignCount].GenRoute()
						newCost = dispatch.Assigns[assignCount].Cost
						if newCost < 0 {
							success = false
						}
					}
					if success {
						bestAssignIdx = assignCount
						bestDelta = newCost
					}
					dispatch.Assigns[assignCount].RemoveShip(trialOrderId)
					dispatch.Assigns[assignCount].GenRoute()
				}
			}
		}

		finalAssignIdx := bestAssignIdx
		if finalAssignIdx < 0 {
			finalAssignIdx = assignCount
		}
		if finalAssignIdx >= MAXASSIGNS {
			finalAssignIdx = MAXASSIGNS - 1
		}

		inserted := false
		if finalAssignIdx < dispatch.AssignsLen {
			inserted = dispatch.Assigns[finalAssignIdx].AddShip(trialOrderId, trialOri, trialDes)
			if inserted {
				dispatch.Assigns[finalAssignIdx].GenRoute()
				if dispatch.Assigns[finalAssignIdx].Cost < 0 {
					dispatch.Assigns[finalAssignIdx].RemoveShip(trialOrderId)
					dispatch.Assigns[finalAssignIdx].GenRoute()
					inserted = false
				}
			}
		} else {
			if assignCount < MAXASSIGNS {
				inserted = dispatch.Assigns[assignCount].AddShip(trialOrderId, trialOri, trialDes)
				if inserted {
					dispatch.Assigns[assignCount].GenRoute()
					if dispatch.Assigns[assignCount].Cost < 0 {
						dispatch.Assigns[assignCount].RemoveShip(trialOrderId)
						dispatch.Assigns[assignCount].GenRoute()
						inserted = false
					} else {
						dispatch.AssignsLen++
						assignCount++
						activeCount++
