							candidateIndices[activeCount-1] = finalAssignIdx
						}
					}
				}
			}
		}

		if !inserted {
			fallbackIdx := assignCount
			if fallbackIdx < MAXASSIGNS {
				ok := dispatch.Assigns[fallbackIdx].AddShip(trialOrderId, trialOri, trialDes)
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
